var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"사실은 전부 알고 있었어요.","JPN":"実は全部知っていたんです。","ENG":"Actually, I already knew everything.","TWN":"其實我全都知道。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇지만 말하지 않았어요. 언니는 보이는 것과 다르게 섬세한 사람이니까.","JPN":"でも、あえて言いませんでした。リタお姉ちゃんは見た目よりもずっと繊細な人だから。","ENG":"But I didn't let on. Rita is more considerate than she seems.","TWN":"但是我沒有說。姐姐跟表面上的她完全不同，是個非常細膩的人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"엄마랑 아빠에 대해 저한테 말하지 않는 이유가 있을 거라고 생각했거든요.","JPN":"お母さんとお父さんについて私に言わなかったのは、理由があると思いました。","ENG":"I figured she must have a reason why she wouldn't tell me the truth about my parents.","TWN":"我覺得爸爸媽媽的事，她一定有不跟我說的理由。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"언젠가는...... 전부 언니한테 들을 수 있을 줄 알았어요.","JPN":"いつか……リタお姉ちゃんから直接聞けると思っていました。","ENG":"So I just thought... she'd tell me about them one day.","TWN":"相信總有一天……姐姐會告訴我的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니, 방금 울음소리 들었어요?","JPN":"リタお姉ちゃん、今の声聞こえましたよね？","ENG":"Did you just hear that, Rita?","TWN":"姐姐，你聽到剛剛那個叫聲了嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"맞아. 타이런트야. 함선을 격추시켰던 놈들 중 하나겠지.","JPN":"ああ、タイラントだ。艦船を撃墜した群れのやつだろう。","ENG":"Yup. It's a Tyrant. Probably one of the jerks that took out the ships.","TWN":"嗯，是侵蝕體暴君。應該是擊落艦船的傢伙中的一個。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"쉽게 따돌릴 거라는 기대는 안 했지만...... 설마 여기까지 추격해 왔나.","JPN":"簡単に引き離せたとは期待してなかったが、まさかここまで追いかけてきたのか。","ENG":"I didn't think we'd lose them this easily... but I didn't expect them to catch up so soon either.","TWN":"雖然早知道無法輕易甩開他……不過沒想到會追來這裡。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"먹을 거라고 해 봤자 사람 둘에 고철 하난데 집요한 녀석들이군.","JPN":"獲物は人間2人に鉄くず1つしかないのに、ずいぶんと執拗な奴らだ。","ENG":"They're pretty persistent, considering there's nothing to eat here except two people and one can of junk.","TWN":"算了算能當食物的不過是兩個人類加一塊廢鐵，還真是難纏的傢伙啊。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"3종 침식체 외, 다수의 침식파 반응이 우리가 있는 방향으로 이동 중입니다.","JPN":"第3種侵食体の他、複数の侵食波反応がこちらの方向に移動中です。","ENG":"In addition to the Category 3 C.O., I detect multiple Corruption Ray signatures headed our way.","TWN":"3類侵蝕體之外，多數侵蝕波反應正在向我們這裡移動。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"적의 진격 속도라면 여기서 이탈한다고 해도 금방 따라잡힐 겁니다.","JPN":"敵の速度だと、ここから離脱したとしてもすぐ追いつかれるでしょう。","ENG":"Given their current speed, they'll catch up to us even if we leave right away.","TWN":"按照敵人的進攻速度，即使我們離開這裡，也很快就會被追上。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"곤란하게 됐군...... 수리를 마치더라도 신호가 잡히려면 시간이 필요해.","JPN":"まいったな……修理を終わらせたとしても、信号を確保するまで時間が必要だ。","ENG":"This isn't good... We'll need time to lock onto the signal even if we finish repairs.","TWN":"問題有些棘手了……即使修理好了，捕捉到信號也需要一些時間。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니, 저 혼자서 시간을 벌어 볼게요.","JPN":"リタお姉ちゃん、私が一人で時間を稼いでみます。","ENG":"I'll try to buy us some time, Rita.","TWN":"姐姐，我來爭取一些時間。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"안 돼. 자살 행위야. 네가 무슨 안토노프 장군인 줄 알아?","JPN":"ダメだ。それはただの自殺行為になる。お前は自分がアントノフ将軍だとでも思ってるのか？","ENG":"No. That's suicidal. Who do you think you are, General Antonov?","TWN":"不行。你這等同於自殺，你以為自己是安東諾夫將軍嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"안토노프 장군님은 아니지만...... 지금 싸울 수 있는 사람은 저뿐이잖아요.","JPN":"アントノフ将軍にはなれないけど……今戦える人は私しかいないでしょう。","ENG":"I'm no General Antonov... but I'm the only one here who can fight right now.","TWN":"雖然我不是瑪麗亞·安東諾夫將軍……但現在能戰鬥的人只有我啊。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"이면세계에 더 오래 머무르다간 언니가 먼저 죽을 거예요.","JPN":"裏世界にこれ以上居続けると、先に死ぬのはリタお姉ちゃんです。","ENG":"You'll die if we linger in the Counterside much longer.","TWN":"如果一直在異界停留下去，姐姐會死的。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 하지만 너한테는 아직 살아 돌아갈 기회가 있어.","JPN":"でもお前にはまだ生きて帰るチャンスがある。","ENG":"True. But you still have a shot at making it back alive.","TWN":"沒錯，但是你還有生還的機會。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"어딘가에 숨어 있어. 나는 이 설비를 다시 기동하게 만들어 둘 테니까.","JPN":"どっかに隠れてろ。私はこの設備が起動できるようにしておくから。","ENG":"Go hide yourself somewhere. I'll get this machine running again.","TWN":"先躲起來，我會把設備重新開機。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"싸우지만 않으면 넌 좀 더 버틸 수 있어. 구조대가 올 동안 최대한 숨어서 버텨.","JPN":"戦闘さえ避ければ、お前はもう少し耐えられる。救助隊が来るまでできるだけ隠れて待つんだ。","ENG":"You'll manage to survive long enough if you don't engage them. Hide as long as you can until the rescue team gets here.","TWN":"只要你不戰鬥就能再堅持一下。躲到救援隊來救你為止。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그런 건 싫어요!","JPN":"そんなのはイヤです！","ENG":"I'm not leaving without you!","TWN":"我不要！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니는 지금 당장 침식 증후군 때문에 죽을지도 모르면서 왜 그렇게 담담해요?!","JPN":"リタお姉ちゃんは今すぐにでも侵食症候群で死ぬかもしれないのに、なんでそんなに冷静でいられるんですか？","ENG":"How could you remain so calm when you could die from the Syndrome any second now?!","TWN":"姐姐現在馬上就要因為侵蝕症候群死了，為什麼還能這麼心平氣和？！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니도 살아서 돌아가고 싶잖아요!","JPN":"リタお姉ちゃんだって生きて帰りたいでしょう！","ENG":"Don't you want to go back alive too?!","TWN":"姐姐不是也希望活著回去嗎！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저는 꼭 집에 가고 싶어요.","JPN":"私は必ず家に帰りたいです。","ENG":"I want to make it back home, no matter what.","TWN":"我一定要回家。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"다 같이 집에 가려면...... 결국 싸울 수밖에 없어요!","JPN":"みんなで帰るためには……戦うしかありません！","ENG":"And for all of us to go back together... I have no choice but to fight!","TWN":"如果想一起回家……除了戰鬥別無選擇！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"기다려, 꼬맹이! 혼자 가서 뭘 어쩌려고!","JPN":"待て、ガキ！　一人で何をするつもりだ！","ENG":"Wait, kid! You can't take them on by yourself!","TWN":"等等，小鬼！你自己一個能幹什麼！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하아...... 하아......!","JPN":"はあ……はあ……！","ENG":"*Huff... Huff...*","TWN":"哈啊……哈啊……！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"젠장......! 애 하나도 못 따라잡아서...... 콜록......!","JPN":"くそっ……！　ガキ一人止められないなんて……ゴホッ！","ENG":"Darn it! I can't even keep up with the kid... *Cough!*","TWN":"可惡……！竟然連個小孩都追不上……咳咳……！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>너도 곧 끝이야. 리타......</color>","JPN":"<color=#ff3636>お前ももうおしまいだ、リタ……</color>","ENG":"<color=#ff3636>You're finished. Rita...</color>","TWN":"<color=#ff3636>你也快不行了，麗塔……</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>바닷속은 춥고 어두웠어...... 그곳은 어떨까......</color>","JPN":"<color=#ff3636>海の底は寒くて暗かった……今お前のいる所はどうなんだろう……</color>","ENG":"<color=#ff3636>It was so cold and dark in that sea... How is it there?</color>","TWN":"<color=#ff3636>海裡又冷又黑……那裡怎麼樣……</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L44_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"저리 꺼져......! 꺼지라고!","JPN":"失せろ……！　消えてしまえ！","ENG":"Get lost! Go away!","TWN":"滾開……！滾！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"다 끝나 버린 일을 나더러 어떡하란 거야! 나는 그저......!","JPN":"もう終わったことを私にどうしろって言うんだ！　私はただ……！","ENG":"What's done is done! What do you expect me to do now?! I was just...","TWN":"事情已經發生了，我能怎麼辦！我只是……！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그저......","JPN":"ただ……","ENG":"It's just that...","TWN":"只是……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"리타, 환청과 환각은 침식 증후군의 대표적인 증상입니다.","JPN":"リタ、幻聴と幻覚は侵食症候群の代表的な症状です。","ENG":"Rita, hallucinations are a key symptom of the Corruption Syndrome.","TWN":"麗塔，幻聽和幻覺是侵蝕症候群的代表症狀。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UNIT_AIR_DRONE_START"},{"id":"L48_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"이렇게 된 이상 대시가 무사할 거라고 믿는 수밖에 없습니다. 최선을 다해 수리를 끝마치십시오.","JPN":"こうなった以上、ダッシュが無事だと信じるしかありません。最善を尽くして修理を終わらせてください。","ENG":"Given your current condition, we'll just have to count on Dash. As for you, focus on completing the repairs.","TWN":"既然已經這樣了，就相信黛西。盡最大努力修理吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......그 녀석은 아직 꼬맹이야. 호라이즌. 믿고 말고 할 문제가 아니라고.","JPN":"……あいつはまだ子どもなんだよ、ホライズン。信じるかどうかの問題じゃない。","ENG":"But she's still just a kid... Horizon. We can't just count on her and hope all is well.","TWN":"……她還是個孩子。地平線，這不是相不相信的問題。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"내가...... 지켜 줘야 하는데......","JPN":"私が……守ってやらないと……","ENG":"I... I'm supposed to protect her...","TWN":"我……要保護她才行啊……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};